/* ═══ INSTALL SCHEDULE PAGE ═══ */
function InstallSchedulePage({jobs}){
  return(<div>
    <h1 style={{fontFamily:'Syne',fontSize:22,fontWeight:800,marginBottom:8}}>Install Schedule</h1>
    <div style={{fontSize:12,color:'#9E9B96',marginBottom:20}}>Field install scheduling and crew coordination</div>
    <div style={{...card,textAlign:'center',padding:60}}>
      <div style={{fontSize:48,marginBottom:12}}>📅</div>
      <div style={{fontSize:16,fontWeight:700,color:'#1A1A1A',marginBottom:6}}>Install Schedule</div>
      <div style={{fontSize:13,color:'#625650'}}>Coming soon — this page will show field install schedules, crew assignments, and upcoming installs.</div>
    </div>
  </div>);
}

/* ═══ SALES — PIPELINE & CONTACTS ═══ */
const LEAD_STAGES=[
  {key:'new_lead',label:'NEW LEAD',color:'#6B7280',bg:'#F9FAFB',accent:'#F4F4F2'},
  {key:'qualifying',label:'QUALIFYING',color:'#1D4ED8',bg:'#EFF6FF',accent:'#DBEAFE'},
  {key:'proposal_sent',label:'PROPOSAL SENT',color:'#B45309',bg:'#FFFBEB',accent:'#FEF3C7'},
  {key:'won',label:'WON',color:'#065F46',bg:'#ECFDF5',accent:'#D1FAE5'},
  {key:'lost',label:'LOST',color:'#991B1B',bg:'#FEF2F2',accent:'#FEE2E2'},
];
const LOSS_REASONS=['Price','Timing','Relationship','Scope Change','Competitor','Customer Canceled','Other'];
const LEAD_SOURCES=['Inbound Call','Referral','Website','Bid Invitation','Cold Outreach','Other'];
const FENCE_TYPES_LEAD=['PC','SW','WI','Mixed','Other'];
const COMPANY_TYPES=['GC','Developer','MUD','Homeowner','Municipality','Other'];

function LeadCard({lead,onDragStart,onClick,linkedJob,onOpenProject,capacity,highlighted}){
  const mc=MC[lead.market]||'#625650';
  const mb=MB[lead.market]||'#F4F4F2';
  const stageDate=lead.stage_entered_at||lead.updated_at||lead.created_at;
  const days=stageDate?Math.floor((Date.now()-new Date(stageDate).getTime())/86400000):0;
  const today=new Date().toISOString().slice(0,10);
  const fuOverdue=lead.follow_up_date&&lead.follow_up_date<today;
  const acv=linkedJob?n(linkedJob.adj_contract_value||linkedJob.contract_value):0;
  const billed=linkedJob?n(linkedJob.ytd_invoiced):0;
  const pct=acv>0?Math.round(billed/acv*100):0;
  return <div draggable onDragStart={e=>onDragStart(e,lead)} onClick={onClick} style={{background:'#FFF',border:highlighted?'2px solid #8A261D':'1px solid #E5E3E0',borderLeft:`4px solid ${mc}`,borderRadius:10,padding:12,marginBottom:8,cursor:'grab',boxShadow:highlighted?'0 0 0 4px #8A261D22,0 1px 3px rgba(0,0,0,0.06)':'0 1px 3px rgba(0,0,0,0.06)',transition:'box-shadow .3s,border-color .3s'}}>
    <div style={{fontWeight:700,fontSize:13,color:'#1A1A1A',marginBottom:4,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis'}}>{lead.company_name||'Unnamed'}</div>
    {lead.project_description&&<div style={{fontSize:11,color:'#625650',marginBottom:6,display:'-webkit-box',WebkitLineClamp:2,WebkitBoxOrient:'vertical',overflow:'hidden'}}>{lead.project_description}</div>}
    <div style={{display:'flex',gap:6,flexWrap:'wrap',marginBottom:6,alignItems:'center'}}>
      {n(lead.estimated_value)>0&&<span style={{fontFamily:'Inter',fontSize:12,fontWeight:800,color:'#8A261D'}}>{$k(lead.estimated_value)}</span>}
      {n(lead.estimated_lf)>0&&<span style={{fontSize:11,color:'#625650'}}>{n(lead.estimated_lf).toLocaleString()} LF</span>}
      {capacity&&n(lead.estimated_lf)>0&&<span title={`Plant backlog: ${capacity.backlog.toLocaleString()} PC LF`} style={{fontSize:10,fontWeight:700,padding:'1px 6px',borderRadius:4,background:capacity.bg,color:capacity.c,border:`1px solid ${capacity.c}33`}}>{capacity.label}</span>}
    </div>
    <div style={{display:'flex',gap:6,alignItems:'center',flexWrap:'wrap'}}>
      {lead.market&&<span style={pill(mc,mb)}>{MS[lead.market]||lead.market}</span>}
      {lead.sales_rep&&<span style={{fontSize:11,color:'#625650'}}>{lead.sales_rep}</span>}
    </div>
    {lead.stage==='won'&&linkedJob&&<div onClick={e=>{e.stopPropagation();onOpenProject&&onOpenProject(linkedJob);}} style={{marginTop:8,padding:'8px 10px',background:'#ECFDF5',border:'1px solid #D1FAE5',borderRadius:8,cursor:'pointer'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:4}}>
        <span style={{fontSize:11,fontWeight:700,color:'#065F46'}}>Project #{linkedJob.job_number} →</span>
        <span style={statusPill(linkedJob.status)}>{SS[linkedJob.status]||linkedJob.status}</span>
      </div>
      {acv>0&&<>
        <div style={{fontSize:10,color:'#625650',marginBottom:3}}>Billed: <b>{pct}%</b> ({$k(billed)} of {$k(acv)})</div>
        <div style={{height:4,background:'#D1FAE5',borderRadius:2,overflow:'hidden'}}><div style={{height:'100%',width:`${Math.min(pct,100)}%`,background:'#10B981'}}/></div>
      </>}
    </div>}
    {lead.stage==='won'&&!linkedJob&&lead.job_number&&<div style={{marginTop:8,padding:'6px 10px',background:'#F4F4F2',borderRadius:8,fontSize:11,color:'#9E9B96'}}>Project #{lead.job_number} — not yet in system</div>}
    <div style={{display:'flex',gap:8,marginTop:6,fontSize:10,color:'#9E9B96',flexWrap:'wrap'}}>
      <span>{days}d in stage</span>
      {lead.follow_up_date&&<span style={{color:fuOverdue?'#B45309':'#9E9B96',fontWeight:fuOverdue?700:400}}>F/U {fD(lead.follow_up_date)}</span>}
      {lead.expected_close_date&&<span>Close {fD(lead.expected_close_date)}</span>}
    </div>
    {onMoveStage&&<StageMover currentStage={lead.stage} onMove={toStage=>onMoveStage(lead,toStage)} stages={LEAD_STAGES}/>}
  </div>;
}

/* ── Stage Mover Strip ── */
function StageMover({currentStage,onMove,stages}){
  const ci=stages.findIndex(s=>s.key===currentStage);
  const prev=ci>0?stages[ci-1]:null;
  const next=ci<stages.length-1?stages[ci+1]:null;
  const[open,setOpen]=React.useState(false);
  return <div style={{marginTop:8,borderTop:'1px solid #F0EFED',paddingTop:6}} onClick={e=>e.stopPropagation()}>
    <div style={{display:'flex',gap:4,alignItems:'center'}}>
      {prev&&<button onClick={e=>{e.stopPropagation();onMove(prev.key);}}
        style={{flex:1,padding:'5px 4px',border:'1px solid #E5E3E0',borderRadius:6,background:'#F9F8F6',cursor:'pointer',fontSize:9,color:'#625650',fontWeight:700,display:'flex',alignItems:'center',justifyContent:'center',gap:2,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis',transition:'all .12s'}}
        onMouseEnter={e=>{e.currentTarget.style.background=prev.bg||'#F4F4F2';e.currentTarget.style.borderColor=prev.color;e.currentTarget.style.color=prev.color;}}
        onMouseLeave={e=>{e.currentTarget.style.background='#F9F8F6';e.currentTarget.style.borderColor='#E5E3E0';e.currentTarget.style.color='#625650';}}>
        &#8592; {prev.label}
      </button>}
      <button onClick={e=>{e.stopPropagation();setOpen(o=>!o);}}
        style={{padding:'5px 7px',border:'1px solid #E5E3E0',borderRadius:6,background:open?'#1A1A1A':'#F9F8F6',cursor:'pointer',fontSize:11,color:open?'#FFF':'#9E9B96',flexShrink:0,lineHeight:1,transition:'all .12s'}}
        title="Move to any stage">
        &#8942;
      </button>
      {next&&<button onClick={e=>{e.stopPropagation();onMove(next.key);}}
        style={{flex:1,padding:'5px 4px',border:'1px solid #E5E3E0',borderRadius:6,background:'#F9F8F6',cursor:'pointer',fontSize:9,color:'#625650',fontWeight:700,display:'flex',alignItems:'center',justifyContent:'center',gap:2,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis',transition:'all .12s'}}
        onMouseEnter={e=>{e.currentTarget.style.background=next.bg||'#F4F4F2';e.currentTarget.style.borderColor=next.color;e.currentTarget.style.color=next.color;}}
        onMouseLeave={e=>{e.currentTarget.style.background='#F9F8F6';e.currentTarget.style.borderColor='#E5E3E0';e.currentTarget.style.color='#625650';}}>
        {next.label} &#8594;
      </button>}
    </div>
    {open&&<div style={{marginTop:5,display:'flex',gap:4,flexWrap:'wrap'}}>
      {stages.filter(s=>s.key!==currentStage).map(s=>(
        <button key={s.key} onClick={e=>{e.stopPropagation();onMove(s.key);setOpen(false);}}
          style={{padding:'3px 8px',border:'1px solid '+s.color,borderRadius:12,background:s.bg||'#F4F4F2',cursor:'pointer',fontSize:9,fontWeight:700,color:s.color,textTransform:'uppercase',letterSpacing:'0.06em',transition:'all .1s'}}
          onMouseEnter={e=>{e.currentTarget.style.background=s.color;e.currentTarget.style.color='#FFF';}}
          onMouseLeave={e=>{e.currentTarget.style.background=s.bg||'#F4F4F2';e.currentTarget.style.color=s.color;}}>
          {s.label}
        </button>
      ))}
    </div>}
  </div>;
}

function NewLeadForm({onClose,onSaved,contacts}){
  const[f,setF]=useState({company_name:'',contact_name:'',contact_phone:'',contact_email:'',project_description:'',market:'',sales_rep:'',source:'',estimated_value:'',estimated_lf:'',fence_type:'PC',expected_close_date:'',follow_up_date:'',notes:''});
  const set=(k,v)=>setF(p=>({...p,[k]:v}));
  const[saving,setSaving]=useState(false);
  const companySuggest=useMemo(()=>{if(!f.company_name||f.company_name.length<2)return[];const q=f.company_name.toLowerCase();return(contacts||[]).filter(c=>(c.company||'').toLowerCase().includes(q)).slice(0,5);},[f.company_name,contacts]);
  const pickCompany=(c)=>{setF(p=>({...p,company_name:c.company||'',contact_name:c.name||p.contact_name,contact_phone:c.phone||p.contact_phone,contact_email:c.email||p.contact_email,market:c.market||p.market}));};
  const save=async()=>{
    if(!f.company_name){alert('Company name required');return;}
    setSaving(true);
    try{
      const body={...f,estimated_value:n(f.estimated_value)||null,estimated_lf:n(f.estimated_lf)||null,stage:'new_lead',stage_entered_at:new Date().toISOString()};
      Object.keys(body).forEach(k=>{if(body[k]==='')body[k]=null;});
      await sbPost('leads',body);
      onSaved&&onSaved();
      onClose();
    }catch(e){alert('Save failed: '+e.message);}
    setSaving(false);
  };
  const fld=(lbl,k,type='text',opts=null)=>(<div style={{marginBottom:10}}>
    <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>{lbl}</div>
    {opts?<select value={f[k]} onChange={e=>set(k,e.target.value)} style={inputS}><option value="">—</option>{opts.map(o=><option key={o} value={o}>{o}</option>)}</select>
    :type==='textarea'?<textarea value={f[k]} onChange={e=>set(k,e.target.value)} style={{...inputS,minHeight:60}}/>
    :<input type={type} value={f[k]} onChange={e=>set(k,e.target.value)} style={inputS}/>}
  </div>);
  return <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.4)',zIndex:500,display:'flex',justifyContent:'flex-end'}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{width:440,maxWidth:'94vw',background:'#F4F4F2',height:'100vh',overflow:'auto',padding:24,boxShadow:'-4px 0 20px rgba(0,0,0,0.15)'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div style={{fontFamily:'Syne',fontSize:20,fontWeight:900,color:'#1A1A1A'}}>New Lead</div>
        <button onClick={onClose} style={{...btnS,padding:'4px 10px'}}>✕</button>
      </div>
      <div style={{...card}}>
        <div style={{marginBottom:10,position:'relative'}}>
          <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Company Name *</div>
          <input value={f.company_name} onChange={e=>set('company_name',e.target.value)} style={inputS}/>
          {companySuggest.length>0&&<div style={{position:'absolute',top:'100%',left:0,right:0,background:'#FFF',border:'1px solid #E5E3E0',borderRadius:6,zIndex:2,maxHeight:150,overflow:'auto'}}>{companySuggest.map(c=><div key={c.id} onClick={()=>pickCompany(c)} style={{padding:'6px 10px',cursor:'pointer',fontSize:12,borderBottom:'1px solid #F4F4F2'}}>{c.company} — {c.name}</div>)}</div>}
        </div>
        {fld('Contact Name','contact_name')}
        {fld('Contact Phone','contact_phone')}
        {fld('Contact Email','contact_email','email')}
        {fld('Project Description','project_description','textarea')}
        {fld('Market','market','text',MKTS)}
        {fld('Sales Rep','sales_rep','text',REPS)}
        {fld('Source','source','text',LEAD_SOURCES)}
        {fld('Estimated Value ($)','estimated_value','number')}
        {fld('Estimated LF','estimated_lf','number')}
        {fld('Fence Type','fence_type','text',FENCE_TYPES_LEAD)}
        {fld('Expected Close Date','expected_close_date','date')}
        {fld('Follow-up Date','follow_up_date','date')}
        {fld('Notes','notes','textarea')}
        <div style={{display:'flex',gap:8,marginTop:16}}>
          <button onClick={onClose} style={{...btnS,flex:1}}>Cancel</button>
          <button onClick={save} disabled={saving} style={{...btnP,flex:2}}>{saving?'Saving...':'Save Lead'}</button>
        </div>
      </div>
    </div>
  </div>;
}

